import React, { useState, useRef, useEffect } from 'react';
import type { Member } from '../types';
import { useMembers } from '../hooks/useMembers';
import { createMember, updateMember } from '../services/memberService';
import { importCsvToFirestore } from '../utils/csvImport';
import { checkMigration, runMigration } from '../utils/assigneeMigration';
import { previewMigration, applyMigration, type MigrationPreview } from '../services/nameMigrationService';
import { NAME_MAP } from '../utils/userNameNormalizer';

interface Props {
  taskCategories: string[];
  kpiCategories: string[];
  ceoMeetingDates: string[];
  onSaveTaskCategories: (cats: string[]) => Promise<void>;
  onSaveKpiCategories: (cats: string[]) => Promise<void>;
  onSaveCeoMeetingDates: (dates: string[]) => Promise<void>;
  onClose: () => void;
  userId?: string;
}

function CategoryEditor({
  label,
  items,
  onSave,
}: {
  label: string;
  items: string[];
  onSave: (items: string[]) => Promise<void>;
}) {
  const [list, setList] = useState([...items]);
  const [newItem, setNewItem] = useState('');
  const [saving, setSaving] = useState(false);

  // 외부(Firestore) 변경 반영
  useEffect(() => {
    setList([...items]);
  }, [items]);

  const add = () => {
    const val = newItem.trim();
    if (!val || list.includes(val)) return;
    const next = [...list, val];
    setList(next);
    setNewItem('');
    setSaving(true);
    onSave(next).finally(() => setSaving(false));
  };

  const remove = (idx: number) => {
    const next = list.filter((_, i) => i !== idx);
    setList(next);
    onSave(next);
  };

  const moveUp = (idx: number) => {
    if (idx === 0) return;
    const next = [...list];
    [next[idx - 1], next[idx]] = [next[idx], next[idx - 1]];
    setList(next);
    onSave(next);
  };

  return (
    <div style={{ marginBottom: 24 }}>
      <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--tm-ink-secondary)', marginBottom: 8 }}>
        {label}
      </div>
      <div style={{ display: 'flex', gap: 8, marginBottom: 8 }}>
        <input
          value={newItem}
          onChange={(e) => setNewItem(e.target.value)}
          onKeyDown={(e) => e.key === 'Enter' && (e.preventDefault(), add())}
          placeholder="새 항목 입력"
          style={{
            flex: 1, padding: '7px 12px',
            border: '1px solid var(--tm-border-default)',
            borderRadius: 'var(--tm-radius-sm)',
            fontSize: 13, fontFamily: 'var(--tm-font)',
            background: 'var(--tm-surface-inset)',
          }}
        />
        <button className="tm-btn-add" onClick={add} disabled={saving} style={{ padding: '7px 14px' }}>
          추가
        </button>
      </div>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
        {list.map((item, idx) => (
          <div key={idx} style={{
            display: 'flex', alignItems: 'center', gap: 8,
            padding: '6px 12px', background: 'var(--tm-surface-inset)',
            borderRadius: 'var(--tm-radius-sm)', fontSize: 13,
          }}>
            <span style={{ flex: 1, fontWeight: 500 }}>{item}</span>
            <button onClick={() => moveUp(idx)} disabled={idx === 0}
              style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--tm-ink-tertiary)', fontSize: 11, opacity: idx === 0 ? 0.3 : 1 }}>▲</button>
            <button onClick={() => remove(idx)}
              style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--tm-urgent)', fontSize: 11 }}>✕</button>
          </div>
        ))}
      </div>
    </div>
  );
}

export default function SettingsPanel({
  taskCategories, kpiCategories, ceoMeetingDates,
  onSaveTaskCategories, onSaveKpiCategories, onSaveCeoMeetingDates,
  onClose,
  userId,
}: Props) {
  const [newMeetingDate, setNewMeetingDate] = useState('');
  const { members } = useMembers();
  const [showMemberForm, setShowMemberForm] = useState(false);
  const [editMember, setEditMember] = useState<Member | null>(null);
  const [migrationInfo, setMigrationInfo] = useState('');
  const [migrationRunning, setMigrationRunning] = useState(false);
  const [namePreview, setNamePreview] = useState<MigrationPreview | null>(null);
  const [nameMigrationRunning, setNameMigrationRunning] = useState(false);
  const [nameMigrationResult, setNameMigrationResult] = useState('');
  const [importing, setImporting] = useState(false);
  const [importProgress, setImportProgress] = useState('');
  const [importResult, setImportResult] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleCsvImport = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !userId) return;

    setImporting(true);
    setImportResult('');
    setImportProgress('가져오기 준비 중...');

    try {
      const result = await importCsvToFirestore(
        file,
        userId,
        (current, total, title) => {
          setImportProgress(`(${current}/${total}) ${title}`);
        },
      );

      const msg = `완료! 생성: ${result.created}건, 건너뜀(중복): ${result.skipped}건` +
        (result.errors.length > 0 ? `\n오류: ${result.errors.join('\n')}` : '');
      setImportResult(msg);
      setImportProgress('');
    } catch (err) {
      setImportResult(`가져오기 실패: ${err instanceof Error ? err.message : String(err)}`);
    } finally {
      setImporting(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  return (
    <div className="tm-modal-overlay" onClick={onClose}>
      <div className="tm-modal" onClick={(e) => e.stopPropagation()} style={{ width: 520, maxHeight: '85vh' }}>
        <h2>설정</h2>

        {/* CSV 가져오기 */}
        <div style={{ marginBottom: 24, padding: 16, background: 'var(--tm-surface-inset)', borderRadius: 'var(--tm-radius-sm)', border: '1px dashed var(--tm-border-default)' }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--tm-ink-secondary)', marginBottom: 8 }}>
            CSV 업무 가져오기
          </div>
          <div style={{ fontSize: 11, color: 'var(--tm-ink-tertiary)', marginBottom: 10 }}>
            업무관리 CSV 파일을 선택하면 상위/하위 업무가 자동으로 등록됩니다. 이미 등록된 업무(같은 제목)는 건너뜁니다.
          </div>
          <input
            ref={fileInputRef}
            type="file"
            accept=".csv"
            onChange={handleCsvImport}
            disabled={importing || !userId}
            style={{ fontSize: 12, fontFamily: 'var(--tm-font)' }}
          />
          {importing && (
            <div style={{ marginTop: 8, fontSize: 12, color: 'var(--tm-brand)' }}>
              {importProgress}
            </div>
          )}
          {importResult && (
            <div style={{
              marginTop: 8, fontSize: 12, padding: '8px 10px',
              background: importResult.startsWith('완료') ? '#e8f5e9' : '#fce4ec',
              borderRadius: 4, whiteSpace: 'pre-wrap',
            }}>
              {importResult}
            </div>
          )}
        </div>

        <CategoryEditor label="업무 분류 관리" items={taskCategories} onSave={onSaveTaskCategories} />
        <CategoryEditor label="KPI 분류 관리" items={kpiCategories} onSave={onSaveKpiCategories} />

        {/* 대표이사 미팅 일정 */}
        <div style={{ marginBottom: 24 }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--tm-ink-secondary)', marginBottom: 8 }}>
            대표이사 미팅 일정
          </div>
          <div style={{ display: 'flex', gap: 8, marginBottom: 8 }}>
            <input
              type="date"
              value={newMeetingDate}
              onChange={(e) => setNewMeetingDate(e.target.value)}
              style={{
                flex: 1, padding: '7px 12px',
                border: '1px solid var(--tm-border-default)',
                borderRadius: 'var(--tm-radius-sm)',
                fontSize: 13, fontFamily: 'var(--tm-font)',
                background: 'var(--tm-surface-inset)',
              }}
            />
            <button className="tm-btn-add" style={{ padding: '7px 14px' }} onClick={() => {
              if (!newMeetingDate || ceoMeetingDates.includes(newMeetingDate)) return;
              onSaveCeoMeetingDates([...ceoMeetingDates, newMeetingDate].sort());
              setNewMeetingDate('');
            }}>추가</button>
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
            {ceoMeetingDates.map((date) => (
              <div key={date} style={{
                display: 'flex', alignItems: 'center', gap: 8,
                padding: '6px 12px', background: 'var(--tm-surface-inset)',
                borderRadius: 'var(--tm-radius-sm)', fontSize: 13,
              }}>
                <span style={{ flex: 1, fontWeight: 500 }}>{date}</span>
                <button onClick={() => onSaveCeoMeetingDates(ceoMeetingDates.filter(d => d !== date))}
                  style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--tm-urgent)', fontSize: 11 }}>✕</button>
              </div>
            ))}
            {ceoMeetingDates.length === 0 && (
              <div style={{ fontSize: 12, color: 'var(--tm-ink-tertiary)', padding: 8 }}>등록된 미팅 일정이 없습니다</div>
            )}
          </div>
        </div>

        {/* 팀원 관리 */}
        <div style={{ marginBottom: 16 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
            <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--tm-ink-secondary)' }}>팀원 관리</div>
            <button className="tm-btn-add" style={{ padding: '5px 12px', fontSize: 11 }}
              onClick={() => { setEditMember(null); setShowMemberForm(true); }}>
              + 팀원
            </button>
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 3 }}>
            {members.map((m) => (
              <div key={m.memberId} style={{
                display: 'flex', alignItems: 'center', gap: 8,
                padding: '6px 12px', background: 'var(--tm-surface-inset)',
                borderRadius: 'var(--tm-radius-sm)', fontSize: 13,
              }}>
                <span style={{ flex: 1, fontWeight: 500 }}>{m.name}</span>
                <span style={{ fontSize: 11, color: 'var(--tm-ink-tertiary)' }}>{m.role} · {m.department}</span>
                <button onClick={() => { setEditMember(m); setShowMemberForm(true); }}
                  style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--tm-brand)', fontSize: 11 }}>수정</button>
                <button onClick={async () => { await updateMember(m.memberId, { isActive: false }); }}
                  style={{ background: 'none', border: 'none', cursor: 'pointer', color: 'var(--tm-urgent)', fontSize: 11 }}>비활성</button>
              </div>
            ))}
            {members.length === 0 && (
              <div style={{ fontSize: 12, color: 'var(--tm-ink-tertiary)', padding: 8 }}>등록된 팀원이 없습니다</div>
            )}
          </div>
        </div>

        {/* 이름 통합 마이그레이션 (광범위 — NAME_MAP 기반) */}
        <div style={{ marginBottom: 16, padding: 16, background: 'var(--tm-surface-inset)', borderRadius: 'var(--tm-radius-sm)', border: '1px dashed var(--tm-border-default)' }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--tm-ink-secondary)', marginBottom: 8 }}>
            영문 이름 → 한글 통합
          </div>
          <div style={{ fontSize: 11, color: 'var(--tm-ink-tertiary)', marginBottom: 10 }}>
            업무 / KPI / 회의록의 담당자·수정자·참석자 필드에 박힌 영문 이름을 한글로 일괄 변환합니다.
          </div>
          <div style={{ fontSize: 11, marginBottom: 10, padding: 8, background: '#fff', borderRadius: 4 }}>
            <strong>매핑:</strong>{' '}
            {Object.entries(NAME_MAP).map(([from, to]) => (
              <span key={from} style={{ marginRight: 12 }}>
                <code>{from}</code> → <strong>{to}</strong>
              </span>
            ))}
          </div>
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
            <button className="tm-btn-add" style={{ padding: '7px 14px' }} disabled={nameMigrationRunning}
              onClick={async () => {
                setNameMigrationRunning(true);
                setNameMigrationResult('');
                try {
                  const preview = await previewMigration();
                  setNamePreview(preview);
                } catch (err: any) {
                  setNameMigrationResult(`오류: ${err.message}`);
                } finally {
                  setNameMigrationRunning(false);
                }
              }}>
              {nameMigrationRunning && !namePreview ? '확인 중...' : '미리보기'}
            </button>
            <button className="tm-btn-save" style={{ padding: '7px 14px' }}
              disabled={nameMigrationRunning || !namePreview || namePreview.total === 0}
              onClick={async () => {
                if (!namePreview || !userId) return;
                if (!window.confirm(`총 ${namePreview.total}건을 변환합니다. 계속하시겠습니까?`)) return;
                setNameMigrationRunning(true);
                try {
                  const result = await applyMigration(namePreview, userId);
                  let msg = `완료! 업데이트 ${result.updated}건, 실패 ${result.failed}건`;
                  if (result.errors.length > 0) {
                    msg += '\n\n[에러]\n' + result.errors.slice(0, 5).join('\n');
                  }
                  setNameMigrationResult(msg);
                  setNamePreview(null);
                } catch (err: any) {
                  setNameMigrationResult(`오류: ${err.message}`);
                } finally {
                  setNameMigrationRunning(false);
                }
              }}>
              적용 ({namePreview?.total ?? 0}건)
            </button>
          </div>
          {namePreview && (
            <div style={{ marginTop: 8, fontSize: 11, padding: '8px 10px', background: '#fff', borderRadius: 4, maxHeight: 240, overflow: 'auto' }}>
              <div style={{ fontWeight: 700, marginBottom: 6 }}>
                변경 대상 총 {namePreview.total}건 — tasks {namePreview.byCollection.tasks} · kpis {namePreview.byCollection.kpis} · meetings {namePreview.byCollection.meetings}
              </div>
              {namePreview.total === 0 ? (
                <div style={{ color: 'var(--tm-ink-tertiary)' }}>변환할 데이터가 없습니다 (이미 정리된 상태입니다)</div>
              ) : (
                <ul style={{ margin: 0, paddingLeft: 16, lineHeight: 1.5 }}>
                  {namePreview.changes.slice(0, 30).map((c, i) => (
                    <li key={i}>
                      <span style={{ color: 'var(--tm-ink-tertiary)' }}>[{c.collection}]</span>{' '}
                      <strong>{c.title || c.docId}</strong>{' '}
                      {c.changes.map((ch, j) => (
                        <span key={j} style={{ marginLeft: 6 }}>
                          {ch.field}: <code>{ch.before}</code> → <code>{ch.after}</code>
                        </span>
                      ))}
                    </li>
                  ))}
                  {namePreview.changes.length > 30 && (
                    <li style={{ color: 'var(--tm-ink-tertiary)' }}>... 외 {namePreview.changes.length - 30}건</li>
                  )}
                </ul>
              )}
            </div>
          )}
          {nameMigrationResult && (
            <pre style={{ marginTop: 8, fontSize: 11, padding: '8px 10px', background: nameMigrationResult.startsWith('완료') ? '#e8f5e9' : '#fce4ec', borderRadius: 4, whiteSpace: 'pre-wrap' }}>
              {nameMigrationResult}
            </pre>
          )}
        </div>

        {/* 담당자 마이그레이션 (이전 도구) */}
        <div style={{ marginBottom: 24, padding: 16, background: 'var(--tm-surface-inset)', borderRadius: 'var(--tm-radius-sm)', border: '1px dashed var(--tm-border-default)' }}>
          <div style={{ fontSize: 13, fontWeight: 700, color: 'var(--tm-ink-secondary)', marginBottom: 8 }}>
            담당자 데이터 정리 (이전 도구)
          </div>
          <div style={{ fontSize: 11, color: 'var(--tm-ink-tertiary)', marginBottom: 10 }}>
            SeonA Choi(대문자) → 최선아 변환, 복수 담당자 → 첫번째만 유지
          </div>
          <div style={{ display: 'flex', gap: 8 }}>
            <button className="tm-btn-add" style={{ padding: '7px 14px' }} disabled={migrationRunning}
              onClick={async () => {
                setMigrationRunning(true);
                try {
                  const info = await checkMigration();
                  let msg = `[확인 결과]\n`;
                  msg += `SeonA Choi: 업무 ${info.seonaChoi.tasks}건, KPI ${info.seonaChoi.kpis}건\n`;
                  msg += `복수 담당자: 업무 ${info.multiAssignee.tasks}건, KPI ${info.multiAssignee.kpis}건\n`;
                  msg += `미배정: 업무 ${info.unassigned.tasks.length}건, KPI ${info.unassigned.kpis.length}건\n`;
                  if (info.unassigned.tasks.length > 0) {
                    msg += `\n[미배정 업무]\n`;
                    info.unassigned.tasks.forEach((t) => { msg += `  ${t.title} · ${t.category} · ${t.dueDate}\n`; });
                  }
                  if (info.unassigned.kpis.length > 0) {
                    msg += `\n[미배정 KPI]\n`;
                    info.unassigned.kpis.forEach((k) => { msg += `  ${k.title} · ${k.period}\n`; });
                  }
                  setMigrationInfo(msg);
                } catch (err: any) {
                  setMigrationInfo(`오류: ${err.message}`);
                } finally {
                  setMigrationRunning(false);
                }
              }}>
              건수 확인
            </button>
            <button className="tm-btn-save" style={{ padding: '7px 14px' }} disabled={migrationRunning}
              onClick={async () => {
                if (!window.confirm('SeonA Choi → 최선아 변환 + 복수 담당자 첫번째만 유지를 실행하시겠습니까?')) return;
                setMigrationRunning(true);
                try {
                  const result = await runMigration();
                  setMigrationInfo(`[완료]\n${result}`);
                } catch (err: any) {
                  setMigrationInfo(`오류: ${err.message}`);
                } finally {
                  setMigrationRunning(false);
                }
              }}>
              마이그레이션 실행
            </button>
          </div>
          {migrationInfo && (
            <pre style={{ marginTop: 8, fontSize: 11, padding: '8px 10px', background: '#f5f5f5', borderRadius: 4, whiteSpace: 'pre-wrap', maxHeight: 200, overflow: 'auto' }}>
              {migrationInfo}
            </pre>
          )}
        </div>

        <div className="tm-form-actions">
          <button className="tm-btn-save" onClick={onClose}>닫기</button>
        </div>

        {showMemberForm && (
          <MemberForm
            member={editMember}
            onSave={async (data) => {
              if (editMember) {
                await updateMember(editMember.memberId, data);
              } else {
                await createMember({ ...data, isActive: true } as any);
              }
              setShowMemberForm(false);
              setEditMember(null);
            }}
            onClose={() => { setShowMemberForm(false); setEditMember(null); }}
          />
        )}
      </div>
    </div>
  );
}

function MemberForm({ member, onSave, onClose }: {
  member: Member | null;
  onSave: (data: Partial<Member>) => Promise<void>;
  onClose: () => void;
}) {
  const [form, setForm] = useState({
    name: member?.name || '',
    email: member?.email || '',
    role: member?.role || '팀원' as '팀장' | '팀원',
    department: member?.department || '',
  });

  return (
    <div className="tm-modal-overlay" style={{ zIndex: 1100 }} onClick={onClose}>
      <div className="tm-modal" onClick={(e) => e.stopPropagation()} style={{ width: 380 }}>
        <h2>{member ? '팀원 수정' : '팀원 추가'}</h2>
        <form onSubmit={(e) => { e.preventDefault(); onSave(form); }}>
          <label>이름 *<input value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} /></label>
          <label>이메일<input value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} /></label>
          <div className="tm-form-row">
            <label>역할
              <select value={form.role} onChange={(e) => setForm({ ...form, role: e.target.value as any })}>
                <option value="팀장">팀장</option>
                <option value="팀원">팀원</option>
              </select>
            </label>
            <label>부서<input value={form.department} onChange={(e) => setForm({ ...form, department: e.target.value })} /></label>
          </div>
          <div className="tm-form-actions">
            <button type="button" className="tm-btn-cancel" onClick={onClose}>취소</button>
            <button type="submit" className="tm-btn-save">{member ? '수정' : '추가'}</button>
          </div>
        </form>
      </div>
    </div>
  );
}
